201→            const words = text ? text.split(/\s+/).length : 0;
202→            setWordCount(words);
203→        })
204→    }, [setWordCount, saveStatus])
205→
206→    const renderSaveStatus = () => {
207→        if (!saveStatus) return null;
208→
209→        let statusText = '';
210→        let statusClass = 'editor-save-status';
211→
212→        switch (saveStatus) {
