166→                    {showCloseConfirm && (
167→                        <motion.div
168→                            className="editor-close-confirm-overlay"
169→                            initial={{ opacity: 0 }}
170→                            animate={{ opacity: 1 }}
171→                            exit={{ opacity: 0 }}
172→                            transition={{ duration: 0.15 }}
173→                        >
174→                            <motion.div
175→                                className="editor-close-confirm-card"
176→                                initial={{ scale: 0.9, opacity: 0 }}
177→                                animate={{ scale: 1, opacity: 1 }}
178→                                exit={{ scale: 0.9, opacity: 0 }}
179→                                transition={{ type: 'spring', stiffness: 300, damping: 25 }}
180→                            >
181→                                <p className="editor-close-confirm-message">
182→                                    {currentDraftIdRef.current ? 'Save changes before closing?' : 'Save as draft before closing?'}
183→                                </p>
184→                                <div className="editor-close-confirm-actions">
185→                                    <button
186→                                        className="editor-close-confirm-discard"
187→                                        onClick={handleConfirmDiscard}
188→                                        disabled={isSavingDraft}
189→                                    >
190→                                        Discard
191→                                    </button>
192→                                    <button
193→                                        className="editor-close-confirm-save"
194→                                        onClick={handleConfirmSaveDraft}
195→                                        disabled={isSavingDraft}
196→                                    >
197→                                        {isSavingDraft ? 'Saving...' : 'Save Draft'}
198→                                    </button>
199→                                </div>
200→                            </motion.div>
201→                        </motion.div>
202→                    )}
203→                </AnimatePresence>
204→            </motion.div>
205→        </div>
206→        </>
207→    )
208→}
209→export default Editor;
