 22→class ErrorBoundary extends React.Component {
 23→  state = { error: null };
 24→  static getDerivedStateFromError(error) {
 25→    return { error };
 26→  }
 27→  render() {
 28→    if (this.state.error) {
 29→      return <div>Error: {this.state.error.message}</div>;
 30→    }
 31→    return this.props.children;
 32→  }
 33→}
 34→
 35→/* theme for mapping css classes to lexical rols */
 36→const theme = {
 37→    paragraph: 'editor-paragraph',
 38→    heading: 'editor-heading',
 39→}
 40→
 41→const formatTimeAgo = (date) => {
 42→    if (!date) return '';
 43→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 44→    if (seconds < 60) return 'just now';
 45→    const minutes = Math.floor(seconds / 60);
 46→    if (minutes < 60) return `${minutes}m ago`;
 47→    const hours = Math.floor(minutes / 60);
 48→    return `${hours}h ago`;
 49→};
 50→
 51→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 52→    const [editor] = useLexicalComposerContext();
 53→    const [editorState, setEditorState] = useState(null);
 54→    const [hasContent, setHasContent] = useState(false);
 55→    const [isSending, setIsSending] = useState(false);
 56→
 57→    // Draft state
 58→    const draftIdRef = useRef(draftId);
 59→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 60→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 61→    const [hasChanges, setHasChanges] = useState(false);
 62→    const saveTimerRef = useRef(null);
 63→    const [, forceUpdate] = useState(0);
 64→
 65→    const {session, user} = useAuth();
 66→
 67→    const queryClient = useQueryClient();
 68→    const userId = user?.userData?.[0]?.id || null;
 69→
 70→    // Keep draftIdRef in sync
 71→    useEffect(() => {
 72→        draftIdRef.current = draftId;
 73→    }, [draftId]);
 74→
 75→    // Tick the "saved X ago" display every 30s
 76→    useEffect(() => {
 77→        if (!lastSavedAt) return;
 78→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 79→        return () => clearInterval(interval);
 80→    }, [lastSavedAt]);
 81→
 82→    const invalidateCreatedJournalQueries = useCallback(async() => {
 83→        const invalidations = [
 84→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
 85→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
 86→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
 87→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
 88→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
 89→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
 90→        ];
 91→
 92→        if(userId){
 93→            invalidations.push(
 94→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
 95→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
 96→            );
 97→        }
 98→
 99→        await Promise.allSettled(invalidations);
100→    }, [queryClient, userId]);
101→
102→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
103→        if (!editorState || !session?.access_token) return;
104→        if (showFeedback) setSaveStatus('saving');
105→
106→        try {
107→            const result = await saveDraft(session.access_token, {
108→                content: editorState,
109→                title: title || '',
110→                draftId: draftIdRef.current || null,
111→                prompt_id: promptId || null,
112→            });
113→
114→            if (result?.id && !draftIdRef.current) {
115→                draftIdRef.current = result.id;
116→                if (onDraftIdCreated) onDraftIdCreated(result.id);
117→            }
118→
119→            setHasChanges(false);
120→            setSaveStatus('saved');
121→            setLastSavedAt(new Date());
122→            if (editorStateRef) {
123→                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
124→            }
125→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
126→        } catch (error) {
127→            console.error('Failed to save draft:', error);
128→            setSaveStatus('unsaved');
129→        }
130→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
131→
132→    // Auto-save every 30 seconds when there are changes
133→    useEffect(() => {
134→        if (!hasChanges || !editorState) return;
135→
136→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
137→        saveTimerRef.current = setTimeout(() => {
138→            handleSaveDraft(false);
139→        }, 30000);
140→
141→        return () => {
142→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
143→        };
144→    }, [editorState, hasChanges, handleSaveDraft]);
145→
146→    const handleClickPublish = async(e, title) => {
147→        e.stopPropagation();
148→        setIsSending(true);
149→
150→        try {
151→            // If we have a draft, publish it
152→            if (draftIdRef.current) {
153→                // Save latest content first
154→                await saveDraft(session.access_token, {
155→                    content: editorState,
156→                    title: title || '',
157→                    draftId: draftIdRef.current,
158→                });
159→
160→                await publishDraft(session.access_token, draftIdRef.current);
161→            } else {
162→                // Direct publish (no draft exists) — use existing save-journal flow
163→                const formdata = new FormData();
164→                if(title && editorState){
165→                    formdata.append('title', title);
166→                    formdata.append('content', editorState);
167→                }
168→                if(promptId){
169→                    formdata.append('prompt_id', promptId);
170→                }
171→                await saveJournal(session?.access_token, formdata);
172→            }
173→
174→            await invalidateCreatedJournalQueries();
175→            setHasContent(false);
176→            onCloseOnSave();
177→            addUploadImagesPath([]);
178→        } catch (error) {
179→            console.error("Error publishing journal:", error);
180→        } finally {
181→            setIsSending(false);
182→        }
183→    }
184→
185→    const onchange = useCallback((state) => {
186→        const jsonb = JSON.stringify(state.toJSON());
187→        setEditorState(jsonb)
188→        setHasChanges(true);
189→        if (saveStatus === 'saved') setSaveStatus('unsaved');
190→
191→        state.read(() => {
192→            const root = $getRoot();
193→
194→            const children = root.getChildren();
195→
196→            const hasEnoughParagraphNodes = children.length > 1
197→            const hasParargraphSize = children[0]?.__size > 0
198→
199→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
200→            setHasContent(hasContent);
201→
202→            // Calculate word count
203→            const text = root.getTextContent().trim();
204→            const words = text ? text.split(/\s+/).length : 0;
205→            setWordCount(words);
206→
207→            // Expose state to parent via ref
208→            if (editorStateRef) {
209→                editorStateRef.current = { hasChanges: true, hasContent, editorState: jsonb, title };
210→            }
211→        })
212→    }, [setWordCount, saveStatus, editorStateRef, title])
213→
214→    const renderSaveStatus = () => {
215→        if (!saveStatus) return null;
216→
217→        let statusText = '';
218→        let statusClass = 'editor-save-status';
219→
220→        switch (saveStatus) {
221→            case 'saving':
222→                statusText = 'Saving...';
223→                statusClass += ' editor-save-status--saving';
224→                break;
225→            case 'saved':
226→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
227→                statusClass += ' editor-save-status--saved';
228→                break;
229→            case 'unsaved':
230→                statusText = 'Unsaved changes';
231→                statusClass += ' editor-save-status--unsaved';
232→                break;
233→            default:
234→                return null;
235→        }
236→
237→        return <span className={statusClass}>{statusText}</span>;
238→    };
239→
240→    return(
241→        <>
242→        {/* Toolbar above content */}
243→        <div className="toolbar-wrapper">
244→            <ToolBar addUploadedImagePath={addUploadImagesPath}/>
245→        </div>
246→
247→        {/* Bar loader directly under toolbar */}
248→        <div className="editor-loader-wrapper">
249→            {isSending && (
250→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
251→            )}
252→        </div>
253→
254→        {/* Editor content area */}
255→        <div className="editor-shell">
256→            <RichTextPlugin
257→            contentEditable={
258→            <ContentEditable
259→            className="editor-input"
260→            aria-placeholder="Write your thoughts here..."
261→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
262→            }
263→            ErrorBoundary={LexicalErrorBoundary}
264→            />
265→
266→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
267→            <MentionPlugin/>
268→            <HistoryPlugin/>
269→            <OnChangePlugin onChange={onchange}/>
270→
271→        </div>
272→
273→        {/* Footer: word count + save status + buttons */}
274→        <div className='editor-footer'>
275→            <div className="editor-footer-left">
276→                <span className="editor-word-count">
277→                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
278→                </span>
279→                {renderSaveStatus()}
280→            </div>
281→            <div className="editor-footer-actions">
282→                <button
283→                    disabled={!hasContent || isSending}
284→                    onClick={() => handleSaveDraft(true)}
285→                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
286→                >
287→                    Save Draft
288→                </button>
289→                <button
290→                    disabled={!title || !hasContent || isSending}
291→                    onClick={(e) => handleClickPublish(e, title)}
292→                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
293→                >
294→                    Publish
295→                </button>
296→            </div>
297→        </div>
298→        </>
299→    )
300→}
301→
302→export default EditorInner;
