 58→    authedGet(token, `/journals/for-you?limit=${limit}&offset=${offset}`, 'Failed to fetch for-you feed');
 59→
 60→export const getInterestSections = (token) =>
 61→    authedGet(token, '/explore/interests', 'Failed to fetch interest sections');
 62→
 63→export const getJournals = async (cursor = null, limit = 5, userId) => {
 64→    let path = cursor
 65→        ? `/journals?limit=${limit}&before=${cursor}`
 66→        : `/journals?limit=${limit}`;
 67→    if (userId) path += `&userId=${userId}`;
 68→    return publicGet(path, 'Failed to fetch journals');
 69→};
