 71→export const getMonthlyHottestJournals = (userId, limit = 10) => {
 72→    const parsedLimit = Number(limit);
 73→    if (Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 10) {
 74→        throw new Error('limit should be an integer between 1 and 10');
 75→    }
 76→    let path = `/journals/hottest-monthly?limit=${parsedLimit}`;
 77→    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
 78→    return publicGet(path, 'failed to fetch monthly hottest journals');
 79→};
